PROCEDURE Inorder(node)
 IF node = NULL THEN
 RETURN
 END IF

 // Traverse left subtree
 Inorder(node.left)

 // Visit root (process node)
 PRINT node.key

 // Traverse right subtree
 Inorder(node.right)
END PROCEDURE

// Example usage: Inorder(root)
// Output for BST: sorted ascending order
